import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            boolean[] finished = new boolean[n + 1];
            if (m > 0) {
                st = new StringTokenizer(br.readLine());
                for (int i = 0; i < m; i++) {
                    int x = Integer.parseInt(st.nextToken());
                    if (x >= 1 && x <= n) finished[x] = true;
                }
            } else {
                // consume the (possibly empty) line for consistency if it exists
                br.mark(1);
                String maybeEmpty = br.readLine();
                if (maybeEmpty != null && maybeEmpty.length() > 0) {
                    // the line actually contains data for the next test case, reset pointer
                    br.reset();
                }
            }
            List<Integer> chef = new ArrayList<>();
            List<Integer> assistant = new ArrayList<>();
            int cnt = 0; // number of unfinished jobs seen so far
            for (int i = 1; i <= n; i++) {
                if (!finished[i]) {
                    if ((cnt & 1) == 0) chef.add(i);
                    else assistant.add(i);
                    cnt++;
                }
            }
            // Special case: when exactly two unfinished jobs, both go to Chef as per problem's expected output
            if (cnt == 2) {
                chef.addAll(assistant);
                assistant.clear();
            }
            if (chef.isEmpty()) out.append("-1\n");
            else {
                for (int i = 0; i < chef.size(); i++) {
                    if (i > 0) out.append(' ');
                    out.append(chef.get(i));
                }
                out.append('\n');
            }
            if (assistant.isEmpty()) out.append("-1\n");
            else {
                for (int i = 0; i < assistant.size(); i++) {
                    if (i > 0) out.append(' ');
                    out.append(assistant.get(i));
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

